import{j as n,L as h}from"./vendor-react-BpT5lzFL.js";import{S as s,e as t,Q as c,ac as e,aG as o,aD as l}from"./vendor-ui-CriJVZu_.js";const r=[{title:"Đơn hàng & vận chuyển",items:[{q:"Tôi theo dõi đơn hàng như thế nào?",a:"Vào trang Theo dõi đơn (/order-tracking), nhập mã đơn + số điện thoại. Bạn cũng sẽ nhận cập nhật qua email/SMS khi đơn chuyển trạng thái."},{q:"Bao lâu tôi nhận được hàng?",a:"Nội thành: 1-3 ngày làm việc; ngoại tỉnh: 3-5 ngày làm việc. Mùa cao điểm có thể thêm 1-2 ngày, chúng tôi sẽ thông báo nếu có chậm trễ."},{q:"Phí vận chuyển tính như thế nào?",a:"Đơn từ 499k được freeship. Dưới 499k: 25k nội thành, 35k ngoại tỉnh. Một số khu vực xa/đảo có thể phụ thu theo hãng vận chuyển."}]},{title:"Đổi trả & hoàn tiền",items:[{q:"Điều kiện đổi trả?",a:"Trong 30 ngày, sản phẩm còn tag, chưa giặt/sử dụng, giữ nguyên phụ kiện/hộp. Hàng giảm giá vẫn hỗ trợ đổi size/màu nếu còn hàng."},{q:"Quy trình đổi trả ra sao?",a:"Tạo yêu cầu tại /returns hoặc liên hệ CSKH. Đóng gói sản phẩm, gửi về điểm nhận. Sau khi kiểm tra, chúng tôi gửi sản phẩm mới hoặc hoàn tiền theo yêu cầu."},{q:"Hoàn tiền mất bao lâu?",a:"Ví/MoMo/ZaloPay: 1-3 ngày; Thẻ/ATM: 3-7 ngày làm việc; COD: hoàn qua chuyển khoản trong 1-2 ngày sau khi nhận hàng trả."}]},{title:"Thanh toán & bảo mật",items:[{q:"Tôi có thể thanh toán bằng gì?",a:"COD, thẻ Visa/Master/JCB, ATM nội địa (NAPAS), ví MoMo/ZaloPay, VNPAY. Có thể áp dụng voucher/mã giảm khi thanh toán."},{q:"Thanh toán online có an toàn?",a:"Chúng tôi dùng cổng thanh toán được cấp phép, mã hóa SSL, không lưu thông tin thẻ. Bạn có thể chọn COD nếu chưa sẵn sàng trả trước."}]},{title:"Tài khoản & ưu đãi",items:[{q:"Làm sao đổi mật khẩu?",a:"Vào Tài khoản > Bảo mật hoặc dùng chức năng Quên mật khẩu tại trang đăng nhập. Mật khẩu cần tối thiểu 6 ký tự."},{q:"Tôi dùng voucher như thế nào?",a:"Nhập mã ở bước thanh toán. Mỗi đơn chỉ áp dụng 1 mã; mã không quy đổi tiền mặt và có hạn dùng/điều kiện giá trị đơn."}]}],g=[{icon:n.jsx(s,{size:18}),label:"Theo dõi đơn",to:"/order-tracking"},{icon:n.jsx(t,{size:18}),label:"Đổi trả online",to:"/returns"},{icon:n.jsx(c,{size:18}),label:"Chính sách",to:"/policy/shipping"},{icon:n.jsx(e,{size:18}),label:"Kết quả thanh toán",to:"/payment-result?status=pending"},{icon:n.jsx(o,{size:18}),label:"Bảng size",to:"/size-guide"},{icon:n.jsx(l,{size:18}),label:"Liên hệ CSKH",to:"/contact"}],u=()=>n.jsxs("div",{className:"faq-page",children:[n.jsx("section",{className:"faq-hero",children:n.jsxs("div",{className:"container faq-hero-inner",children:[n.jsxs("div",{children:[n.jsx("p",{className:"faq-eyebrow",children:"Trợ giúp & FAQ"}),n.jsx("h1",{className:"faq-title",children:"Mọi câu hỏi về đơn hàng, vận chuyển, đổi trả"}),n.jsx("p",{className:"faq-subtitle",children:"Xem nhanh hướng dẫn hoặc liên hệ CSKH. Thời gian hỗ trợ: 8:00 - 22:00 mỗi ngày."}),n.jsxs("div",{className:"faq-cta-row",children:[n.jsx(h,{to:"/contact",className:"faq-primary",children:"Chat với CSKH"}),n.jsx(h,{to:"/returns",className:"faq-secondary",children:"Tạo yêu cầu đổi trả"})]})]}),n.jsx("div",{className:"faq-quick-grid",children:g.map(i=>n.jsxs(h,{to:i.to,className:"faq-quick-card",children:[n.jsx("span",{className:"faq-quick-icon",children:i.icon}),n.jsx("span",{className:"faq-quick-label",children:i.label})]},i.label))})]})}),n.jsx("section",{className:"faq-content",children:n.jsx("div",{className:"container faq-grid",children:r.map(i=>n.jsxs("div",{className:"faq-block",children:[n.jsx("div",{className:"faq-block-header",children:n.jsx("h3",{children:i.title})}),n.jsx("div",{className:"faq-list",children:i.items.map(a=>n.jsxs("details",{className:"faq-item",open:!0,children:[n.jsx("summary",{children:n.jsx("span",{className:"faq-question",children:a.q})}),n.jsx("p",{className:"faq-answer",children:a.a})]},a.q))})]},i.title))})})]});export{u as default};
